  cl_order_id, product_id, lot_no, reserved_qty, reserved_at
) VALUES (
  #{clOrderId}, #{productId}, #{lotNo}, #{reservedQty}, NOW()
)

mapper.delete:
DELETE FROM stock_reservation
WHERE cl_order_id = #{clOrderId}
