mapper.select:
SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE cl_order_id = #{clOrderId}
  AND product_id = #{productId}

SELECT COALESCE(SUM(reserved_qty), 0)
